@namespace Lumeo

@{
    var context = new DialogContext(EffectiveOpen, EventCallback.Factory.Create<bool>(this, SetOpen), _titleId, _descriptionId, TryDismiss);
}

<CascadingValue Value="context" IsFixed="false">
    @ChildContent
</CascadingValue>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public bool Open { get; set; }
    [Parameter] public EventCallback<bool> OpenChanged { get; set; }

    /// <summary>
    /// Uncontrolled initial open state. Used only when the consumer does NOT
    /// bind <see cref="Open"/> (Radix <c>defaultOpen</c>): the dialog then owns
    /// its open state internally, seeded from this value. When <see cref="Open"/>
    /// is supplied the component is controlled and this is ignored.
    /// </summary>
    [Parameter] public bool DefaultOpen { get; set; }

    /// <summary>
    /// Fires before any user-initiated dismiss (Escape, backdrop click,
    /// X button, or a <c>DialogClose</c> trigger). Set
    /// <see cref="DismissEventArgs.Cancel"/> to <c>true</c> to abort the
    /// dismiss — useful for "discard unsaved changes?" guards.
    /// Inspect <see cref="DismissEventArgs.Reason"/> to find out which
    /// gesture asked to close.
    /// </summary>
    [Parameter] public EventCallback<DismissEventArgs> OnBeforeClose { get; set; }

    [Obsolete("Use Open instead. IsOpen will be removed in a future release.")]
    [Parameter] public bool IsOpen { get => Open; set => Open = value; }

    [Obsolete("Use OpenChanged instead. IsOpenChanged will be removed in a future release.")]
    [Parameter] public EventCallback<bool> IsOpenChanged { get => OpenChanged; set => OpenChanged = value; }

    private readonly string _titleId = LumeoIds.New("dialog-title");
    private readonly string _descriptionId = LumeoIds.New("dialog-desc");

    // Uncontrolled state. _controlled is set in SetParametersAsync when the
    // consumer supplies Open/IsOpen; otherwise the dialog owns _open (Radix
    // controlled-vs-uncontrolled disambiguation — a bool param can't be
    // "undefined", so we inspect which parameters were actually provided).
    private bool _controlled;
    private bool _open;

    private bool EffectiveOpen => _controlled ? Open : _open;

    public override Task SetParametersAsync(ParameterView parameters)
    {
        // The legacy IsOpen alias is obsolete but still a valid bound parameter,
        // so we must honour it when deciding controlled-ness (suppress CS0618 for
        // the nameof — we're intentionally probing the alias).
#pragma warning disable CS0618
        _controlled = parameters.TryGetValue<bool>(nameof(Open), out _)
            || parameters.TryGetValue<bool>(nameof(IsOpen), out _)
            || OpenChanged.HasDelegate;
#pragma warning restore CS0618
        return base.SetParametersAsync(parameters);
    }

    protected override void OnInitialized()
    {
        if (!_controlled) _open = DefaultOpen;
    }

    private async Task SetOpen(bool value)
    {
        // Mirror the new state onto Open so two-way @bind-Open consumers and the
        // uncontrolled internal state stay in sync; OpenChanged drives controlled
        // consumers.
        _open = value;
        Open = value;
        await OpenChanged.InvokeAsync(value);
        // Re-render so the cascaded context picks up EffectiveOpen. The close
        // paths (Escape / backdrop / DialogClose) call this via TryDismiss as a
        // direct method call — without an explicit StateHasChanged an uncontrolled
        // dialog (no OpenChanged) would never re-render and so never close.
        StateHasChanged();
    }

    private async Task<bool> TryDismiss(string reason)
    {
        if (OnBeforeClose.HasDelegate)
        {
            var args = new DismissEventArgs { Reason = reason };
            await OnBeforeClose.InvokeAsync(args);
            if (args.Cancel) return false;
        }
        await SetOpen(false);
        return true;
    }

    public record DialogContext(bool IsOpen, EventCallback<bool> SetOpen, string TitleId, string DescriptionId, Func<string, Task<bool>> TryDismiss);
}

@namespace Lumeo

<div class="@CssClass" role="button" tabindex="0" @onclick="Close" @onkeydown="HandleKeyDown" @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    [CascadingParameter] public Dialog.DialogContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("inline-flex", Class);

    // Route through TryDismiss so OnBeforeClose handlers can guard the
    // close from a custom button just like the built-in X / Escape paths.
    private async Task Close() => await Context.TryDismiss("close");

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key is "Enter" or " ") await Close();
    }
}

@namespace Lumeo
@using Lumeo.Services
@implements IAsyncDisposable

@if (Shell is not null)
{
    @* See OverlayShellMarker — host DialogContent already painted the shell.
       Pass children through to avoid a second backdrop + panel. *@
    @ChildContent
}
else if (Context.IsOpen)
{
    <div class="fixed inset-0 flex items-center justify-center" style="z-index:@BackdropZ">
        @* Backdrop — theme-aware overlay token. Uses the --color-overlay-backdrop
           CSS variable (defined + light/dark-swapped in lumeo.css) directly via
           inline style rather than a Tailwind utility, so it resolves for every
           consumer of the pre-built bundle without depending on the token class
           being safelisted (same approach as Tour's SVG scrim). *@
        <div class="fixed inset-0 animate-fade-in" style="background-color:var(--color-overlay-backdrop);z-index:@BackdropZ" @onclick="HandleBackdropClick"></div>
        <!-- Content -->
        @* @onkeydown:stopPropagation — a modal surface owns the keys pressed
           inside it. Nested overlays render INSIDE this div, so their keydown
           events bubble here; without this, an Escape already handled by an
           inner Dialog/Sheet/Drawer/AlertDialog would also fire this dialog's
           Escape handler and cascade-close every ancestor overlay. The
           directive is static (stops ALL keydown propagation at this element's
           boundary), which is safe for a modal: descendants still receive
           their events first — propagation is only cut once it reaches this
           div — and nothing outside an open modal should react to its keys. *@
        <div id="@_contentId" class="@CssClass" style="z-index:@ContentZ" role="dialog" aria-modal="true" aria-labelledby="@Context.TitleId" aria-describedby="@Context.DescriptionId" @onkeydown="HandleKeyDown" @onkeydown:stopPropagation tabindex="-1" @attributes="AdditionalAttributes">
            @if (Scrollable)
            {
                <div class="max-h-[85vh] overflow-y-auto">
                    @ChildContent
                </div>
            }
            else
            {
                @ChildContent
            }
            @if (!PreventClose)
            {
                <button type="button" aria-label="@L["Dialog.Close"]" class="absolute end-2 top-2 sm:end-4 sm:top-4 inline-flex items-center justify-center rounded-sm h-11 w-11 sm:h-6 sm:w-6 opacity-70 transition-opacity hover:opacity-100 focus:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2" @onclick="HandleCloseButton">
                    <Blazicon Svg="Lucide.X" class="h-4 w-4" />
                    <span class="sr-only">@L["Dialog.Close"]</span>
                </button>
            }
        </div>
    </div>
}

@inject IComponentInteropService Interop
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@code {
    [CascadingParameter] public Dialog.DialogContext Context { get; set; } = default!;
    [CascadingParameter] public OverlayShellMarker? Shell { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public bool PreventClose { get; set; }
    [Parameter] public DialogSize Size { get; set; } = DialogSize.Default;
    [Parameter] public bool Scrollable { get; set; }
    [Parameter] public string? Class { get; set; }
    /// <summary>
    /// Backdrop z-index. Content sits at <c>ZIndex + 1</c>. Defaults to
    /// <see cref="OverlayService.BaseZIndex"/>; <see cref="OverlayProvider"/>
    /// supplies an incrementing value per nested overlay so a Dialog opened
    /// from inside another Dialog stacks above instead of colliding.
    /// </summary>
    [Parameter] public int ZIndex { get; set; } = OverlayService.BaseZIndex;
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _contentId = LumeoIds.New("dialog");
    private bool _wasOpen;

    private int BackdropZ => ZIndex;
    private int ContentZ => ZIndex + 1;

    private string SizeClass => Size switch
    {
        DialogSize.Sm => "max-w-sm",
        DialogSize.Default => "max-w-lg",
        DialogSize.Lg => "max-w-2xl",
        DialogSize.Xl => "max-w-4xl",
        DialogSize.Full => "max-w-[calc(100vw-2rem)] max-h-[calc(100vh-2rem)]",
        _ => "max-w-lg"
    };

    private string CssClass => Cx.Merge("relative grid w-full", SizeClass, "gap-4 bg-background p-6 shadow-lg animate-zoom-in sm:rounded-lg", Class);

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        // Passthrough mode — host DialogContent owns lifecycle effects.
        if (Shell is not null) return;

        if (Context.IsOpen && !_wasOpen)
        {
            await Interop.LockScroll();
            await Interop.SetupFocusTrap(_contentId);
            _wasOpen = true;
        }
        else if (!Context.IsOpen && _wasOpen)
        {
            await Cleanup();
            _wasOpen = false;
        }
    }

    private Task HandleBackdropClick() => PreventClose ? Task.CompletedTask : Dismiss("outside");

    private Task HandleCloseButton() => Dismiss("close");

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Escape" && !PreventClose)
        {
            await Dismiss("escape");
        }
    }

    private Task Dismiss(string reason) => Context.TryDismiss(reason);

    private async Task Cleanup()
    {
        try
        {
            await Interop.RemoveFocusTrap(_contentId);
            await Interop.UnlockScroll();
        }
        catch (JSDisconnectedException) { }
    }

    public async ValueTask DisposeAsync()
    {
        if (_wasOpen)
        {
            await Cleanup();
        }
    }

    public enum DialogSize { Sm, Default, Lg, Xl, Full }
}

